#include<bits/stdc++.h>
using namespace std;
const int NM = 1500+5 ;
int n,m,k,h[NM][NM],s[NM][NM],z[NM][NM];
int a[NM][NM],b[NM][NM],c[NM][NM],d[NM][NM];
int p[NM],q[NM],ans;
void init_S(){
	for(int i=1;i<=n;i++)
		for(int j=1;j<=m;j++)
			s[i][j]=s[i-1][j]+s[i][j-1]-s[i-1][j-1]+h[i][j];
	return;
}
void init_Z(){
	for(int i=k;i<=n;i++)
		for(int j=k;j<=m;j++)
			z[i][j]=s[i][j]-s[i-k][j]-s[i][j-k]+s[i-k][j-k];
	return;
}
void init_PQ(){
	for(int i=k;i<=n;i++)
		for(int j=k;j<=m;j++)
			p[i]=max(p[i],z[i][j]);
	for(int j=k;j<=m;j++)
		for(int i=k;i<=n;i++)
			q[j]=max(q[j],z[i][j]);
	return;
}
void init_A(){
	for(int i=k;i<=n;i++)
		for(int j=k;j<=m;j++)
			a[i][j]=max(z[i][j],max(a[i-1][j],a[i][j-1]));
	return;
}
void init_B(){
	for(int i=k;i<=n;i++)
		for(int j=m-k+1;j>=1;j--)
			b[i][j]=max(z[i][j+k-1],max(b[i-1][j],b[i][j+1]));
	return;
}
void init_C(){
	for(int i=n-k+1;i>=1;i--)
		for(int j=k;j<=m;j++)
			c[i][j]=max(z[i+k-1][j],max(c[i+1][j],c[i][j-1]));
	return;
}
void init_D(){
	for(int i=n-k+1;i>=1;i--)
		for(int j=m-k+1;j>=1;j--)
			d[i][j]=max(z[i+k-1][j+k-1],max(d[i+1][j],d[i][j+1]));
	return;
}
void solve(){
	for(int i=k;i+2*k<=n;i++)
		ans=max(ans,a[i][m]+p[i+k]+d[i+k+1][1]);
	for(int j=k;j+2*k<=m;j++)
		ans=max(ans,c[1][j]+q[j+k]+d[1][j+k+1]);
	for(int i=k;i+k<=n;i++)
		for(int j=k;j+k<=m;j++){
			ans=max(ans,a[i][j]+b[i][j+1]+d[i+1][1]);
			ans=max(ans,a[n][j]+b[i][j+1]+d[i+1][j+1]);
			ans=max(ans,a[i][m]+c[i+1][j]+d[i+1][j+1]);
			ans=max(ans,a[i][j]+c[i+1][j]+d[1][j+1]);
		}
	cout<<ans;
	return;
}
int main(){
	cin>>m>>n>>k;swap(m,n);
	for(int i=1;i<=n;i++)
		for(int j=1;j<=m;j++)cin>>h[i][j];
	init_S();init_Z();init_PQ();
	init_A();init_B();init_C();init_D();
	solve();
	return 0;
}
